"use strict";(globalThis.webpackChunkfptcloud_docs=globalThis.webpackChunkfptcloud_docs||[]).push([[63967],{337512(e,n,t){t.r(n),t.d(n,{assets:()=>c,contentTitle:()=>o,default:()=>h,frontMatter:()=>a,metadata:()=>s,toc:()=>l});const s=JSON.parse('{"id":"managed-fpt-kubernetes-engine-2/gpu-sharing","title":"Managed \u2013 FPT Kubernetes Engine","description":"2. Managed \u2013 FPT Kubernetes Engine","source":"@site/i18n/en/docusaurus-plugin-content-docs/current/managed-fpt-kubernetes-engine-2/gpu-sharing.md","sourceDirName":"managed-fpt-kubernetes-engine-2","slug":"/managed-fpt-kubernetes-engine-2/gpu-sharing","permalink":"/en/managed-fpt-kubernetes-engine-2/gpu-sharing","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"sidebar_label":"Managed \u2013 FPT Kubernetes Engine","title":"Managed \u2013 FPT Kubernetes Engine","source":"https://fptcloud.com/en/documents/managed-fpt-kubernetes-engine-2/?doc=gpu-sharing","parent":"https://fptcloud.com/en/documents/managed-fpt-kubernetes-engine-2","lang":"en","converted":"2026-03-19","sidebar_class_name":"hidden"},"sidebar":"defaultSidebar","previous":{"title":"Managed \u2013 FPT Kubernetes Engine","permalink":"/en/managed-fpt-kubernetes-engine-2/gpu-fpt-cloud"},"next":{"title":"Managed \u2013 FPT Kubernetes Engine","permalink":"/en/managed-fpt-kubernetes-engine-2/how-to-use-gpu-in-kubernetes"}}');var i=t(474848),r=t(28453);const a={sidebar_label:"Managed \u2013 FPT Kubernetes Engine",title:"Managed \u2013 FPT Kubernetes Engine",source:"https://fptcloud.com/en/documents/managed-fpt-kubernetes-engine-2/?doc=gpu-sharing",parent:"https://fptcloud.com/en/documents/managed-fpt-kubernetes-engine-2",lang:"en",converted:"2026-03-19",sidebar_class_name:"hidden"},o="Managed \u2013 FPT Kubernetes Engine",c={},l=[];function d(e){const n={a:"a",h1:"h1",header:"header",hr:"hr",img:"img",li:"li",ol:"ol",p:"p",ul:"ul",...(0,r.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.header,{children:(0,i.jsx)(n.h1,{id:"managed--fpt-kubernetes-engine",children:"Managed \u2013 FPT Kubernetes Engine"})}),"\n",(0,i.jsxs)(n.ol,{start:"2",children:["\n",(0,i.jsx)(n.li,{children:"Managed \u2013 FPT Kubernetes Engine"}),"\n"]}),"\n",(0,i.jsx)(n.p,{children:"GPU Sharing"}),"\n",(0,i.jsxs)(n.ul,{children:["\n",(0,i.jsx)(n.li,{children:(0,i.jsx)(n.a,{href:"https://www.facebook.com/sharer/sharer.php?u=https%3A%2F%2Ffptcloud.com%2Fen%2Fdocuments%2Fmanaged-fpt-kubernetes-engine-2%2F",children:" "})}),"\n",(0,i.jsx)(n.li,{children:(0,i.jsx)(n.a,{href:"https://www.linkedin.com/sharing/share-offsite/?url=https%3A%2F%2Ffptcloud.com%2Fen%2Fdocuments%2Fmanaged-fpt-kubernetes-engine-2%2F",children:" "})}),"\n",(0,i.jsx)(n.li,{children:(0,i.jsx)(n.a,{href:"https://twitter.com/share?text=&url=https%3A%2F%2Ffptcloud.com%2Fen%2Fdocuments%2Fmanaged-fpt-kubernetes-engine-2%2F",children:" "})}),"\n"]}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"One of the significant advantages of using GPUs on K8s is the ability to share GPUs. Most workloads do not require the full memory and computing resources of individual GPUs. Therefore, sharing GPUs among multiple processes is essential to increase GPU utilization and reduce infrastructure costs."}),"\n",(0,i.jsx)(n.p,{children:"GPU sharing currently has three mechanisms:"}),"\n",(0,i.jsxs)(n.ol,{children:["\n",(0,i.jsxs)(n.li,{children:["\n",(0,i.jsx)(n.p,{children:"Time Slicing:"}),"\n"]}),"\n",(0,i.jsxs)(n.li,{children:["\n",(0,i.jsx)(n.p,{children:"Multi-instance GPU (MIG)"}),"\n"]}),"\n",(0,i.jsxs)(n.li,{children:["\n",(0,i.jsx)(n.p,{children:"Multi-Process Service (MPS):"}),"\n"]}),"\n"]}),"\n",(0,i.jsx)(n.p,{children:"Time slicing is a mechanism that allows GPU workloads to be interleaved with each other. It utilizes a GPU time-slicing scheduler to concurrently execute multiple CUDA processes through time-sharing."}),"\n",(0,i.jsx)(n.p,{children:"When Time slicing is activated, the GPU will share its resources among various processes in a fair-sharing manner by switching between processes at regular intervals. This mechanism introduces overhead as a result of continuous process switching, leading to frame stuttering and increased latency. Additionally, Time slicing lacks a memory isolation mechanism between shared GPU processes or any memory allocation limits, which can result in frequent Out-of-Memory (OOM) errors."}),"\n",(0,i.jsx)(n.p,{children:"Multi-Instance GPU (MIG) is an architecture available on NVIDIA that enables the subdivision of a GPU into separate GPU partitions. These partitions are isolated from each other in terms of memory bandwidth, cache memory, and processing cores."}),"\n",(0,i.jsx)(n.p,{children:"With MIG, each instance's graphics processor is independent and has its own dedicated memory system. The on-chip port crossbar, L2 cache, memory controllers, and DRAM bus addresses are uniquely assigned to each instance. This ensures fault tolerance, and the application's workload can be computed with throughput and latency on each individual instance."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.img,{src:"https://fptcloud.com/wp-content/uploads/2023/11/65-1.png",alt:""})}),"\n",(0,i.jsx)(n.p,{children:'These independent GPU partitions (MIG) are named according to a format indicating the device\'s memory and compute resources, for example, "1g.gb" corresponds to a GPU slice with 6 GB of memory.'}),"\n",(0,i.jsx)(n.p,{children:"MIG does not allow the creation of GPU partitions with custom sizes and quantities, as each GPU model supports only a specific set of MIG configurations depending on the hardware configuration of the device. This limits resource optimization when utilizing the GPU. Furthermore, MIG devices must adhere to specific arrangement rules, further restricting the flexibility of their usage."}),"\n",(0,i.jsx)(n.p,{children:"MIG is a GPU sharing method that provides the highest level of isolation between processes. However, this mechanism lacks flexibility and is only compatible with certain GPU architectures (Ampere and Hopper)."}),"\n",(0,i.jsx)(n.p,{children:"In the context of Kubernetes (K8s), NVIDIA has developed the GPU Operator to facilitate MIG usage, although there are still limitations. Users utilize a ConfigMap to define a set of MIG configurations that can be applied to each node by labeling that node."}),"\n",(0,i.jsx)(n.p,{children:"To efficiently use GPU resources in a K8s cluster, users must continuously modify the ConfigMap to adjust MIG sizes to meet the changing resource requirements of workloads. This process is inconvenient, even though configuring MIG is an improvement over directly accessing nodes and manually creating/deleting MIG devices. Nevertheless, it still requires effort and time. As a result, MIG device configurations are rarely modified over time or are not applied at all, leading to significant inefficiency in GPU utilization and suboptimal GPU usage costs. This issue is addressed by the use of the Automatic GPU Partitioning (MPS) mechanism."}),"\n",(0,i.jsx)(n.p,{children:"Multi-Process Service (MPS) utilizes the client-server model of the CUDA API, enabling the simultaneous execution of multiple processes on the same GPU."}),"\n",(0,i.jsx)(n.p,{children:"The server manages GPU access rights concurrently among clients. Clients connect to the server through the client runtime, integrated into the CUDA Driver library and transparent to the application."}),"\n",(0,i.jsx)(n.p,{children:"Fundamentally, MPS is compatible with all current GPUs, providing the highest flexibility, allowing the creation of GPU partitions with options for both memory capacity and computational capabilities. However, the MPS mechanism does not truly isolate the entire memory space between processes. In most cases, MPS demonstrates a good compromise between MIG and Time-slicing."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.img,{src:"https://fptcloud.com/wp-content/uploads/2023/11/66.png",alt:""})}),"\n",(0,i.jsx)(n.p,{children:"Compared to Time-slicing, MPS eliminates the overhead of context switching by running processes in parallel through spatial sharing, leading to improved computational performance. Furthermore, MPS allocates a separate GPU memory address space for each process, addressing the limitations of Time-slicing."}),"\n",(0,i.jsx)(n.p,{children:"However, in MPS, processes are not completely isolated from each other. Although MPS allows limiting the memory and computational resources of a client, it does not provide error isolation and memory protection. This means that a process encountering an issue can lead to a GPU reset, affecting all other processes running on the GPU. NVIDIA Kubernetes does not currently support MPS partitioning, so using MPS on Kubernetes requires third-party software."}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.a,{href:"./why-you-should-use-gpu-in-k8s",children:" Previous Why you should use GPU in K8s? "})," ",(0,i.jsx)(n.a,{href:"./gpu-fpt-cloud-k8s",children:" Next GPU on FPT Cloud's K8s "})]})]})}function h(e={}){const{wrapper:n}={...(0,r.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},28453(e,n,t){t.d(n,{R:()=>a,x:()=>o});var s=t(296540);const i={},r=s.createContext(i);function a(e){const n=s.useContext(r);return s.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function o(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),s.createElement(r.Provider,{value:n},e.children)}}}]);